SELECT AVG(a1c_percentage) AS average_a1c
  FROM a1c_records
  WHERE patient_id = 1;

SELECT MIN(a1c_percentage) AS lowest_a1c
FROM a1c_records
WHERE patient_id = 1;

SELECT AVG(a1c_change) AS average_a1c_change
FROM patient_treatments
WHERE treatment_outcome = 'Completed';

SELECT a1c_percentage
FROM a1c_records
WHERE patient_id = 1;

SELECT treatment_outcome
FROM patient_treatments
WHERE achieved_a1c_below_7 = 1;

SELECT treatment_name
FROM treatments
ORDER BY treatment_name;
